import { Link } from "react-router-dom";

const AdminDashboard = () => (
  <div>
    <h2>Admin Panel</h2>
    <Link to="/admin/users">Users</Link><br/>
    <Link to="/admin/orders">Orders</Link><br/>
    <Link to="/admin/products">Products</Link>
  </div>
);

export default AdminDashboard;
